                      onChange={(e) => setOfferMessage(e.target.value)}
                      className="min-h-32 resize-none"
                      data-testid="textarea-offer-message"
                    />
                    <p className="text-xs text-muted-foreground">This message will be visible only to the requester</p>
                  </div>

