                      }}
                      className="flex-1 gap-2 bg-primary hover:bg-primary/90"
                      data-testid="button-send-message-search"
                    >
                      <MessageSquare className="w-4 h-4" /> Send
                    </Button>
                  </div>
                </CardContent>
              </Card>
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </div>
  );
}

