import { useState } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Loader2, ShieldCheck, CreditCard } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { useWallet } from "@/hooks/use-wallet";
import { useToast } from "@/hooks/use-toast";
import { calculatePTF } from "@/utils/calculate-ptf";

interface WalletDepositModalProps {
  isOpen: boolean;
  onClose: () => void;
}

export function WalletDepositModal({ isOpen, onClose }: WalletDepositModalProps) {
  const [step, setStep] = useState<"amount" | "confirm" | "processing" | "success">("amount");
  const [depositAmount, setDepositAmount] = useState("");
  const { deposit } = useWallet();
  const { toast } = useToast();

  const amount = parseInt(depositAmount) || 0;
  const fee = amount >= 5 ? calculatePTF(amount) : 0;
  const total = amount + fee;

  const handleNext = () => {
    if (amount < 100) {
      toast({
        title: "Invalid Amount",
        description: "Minimum deposit is ₦100",
        variant: "destructive",
      });
      return;
    }
    setStep("confirm");
  };

  const handleConfirm = async () => {
    setStep("processing");
    // Simulate Korapay processing
    await new Promise((resolve) => setTimeout(resolve, 2500));
    setStep("success");

    // Deposit the money
    deposit(amount, fee);

    // Auto close and reset
    setTimeout(() => {
      onClose();
      setStep("amount");
      setDepositAmount("");
    }, 1500);
  };

  const handleClose = () => {
    if (step === "processing") return; // Don't close during processing
    onClose();
    setStep("amount");
    setDepositAmount("");
  };

  return (
    <Dialog open={isOpen} onOpenChange={handleClose}>
      <DialogContent className="sm:max-w-md">
        <AnimatePresence mode="wait">
          {step === "amount" && (
            <motion.div
              key="amount"
              initial={{ opacity: 0, x: -20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: 20 }}
            >
              <DialogHeader>
                <DialogTitle className="flex items-center gap-2 text-xl">
                  <span className="bg-primary/10 p-2 rounded-lg text-primary">
                    <ShieldCheck className="w-5 h-5" />
                  </span>
                  Deposit to Wallet
                </DialogTitle>
                <DialogDescription>
                  Add funds to your wallet using Korapay. Secure and instant.
                </DialogDescription>
              </DialogHeader>

              <div className="py-6 space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="deposit-amount">Amount (₦)</Label>
                  <Input
                    id="deposit-amount"
                    type="number"
                    placeholder="Enter amount (minimum ₦100)"
                    value={depositAmount}
                    onChange={(e) => setDepositAmount(e.target.value)}
                    className="text-lg h-12"
                    min="100"
                  />
                  <p className="text-xs text-muted-foreground">
                    Minimum: ₦100 | No maximum limit
                  </p>
                </div>

                {amount > 0 && (
                  <motion.div
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="bg-slate-50 dark:bg-slate-900 p-4 rounded-xl space-y-3 border border-slate-100 dark:border-slate-800"
                  >
                    <div className="flex justify-between text-sm">
                      <span className="text-muted-foreground">Deposit Amount</span>
                      <span className="font-medium">₦{amount.toLocaleString()}</span>
                    </div>
                    <div className="flex justify-between text-sm">
                      <span className="text-muted-foreground">Platform Protection Fee (PTF)</span>
                      <span className="font-medium text-orange-600">₦{fee.toLocaleString()}</span>
                    </div>
                    <div className="h-px bg-border" />
                    <div className="flex justify-between text-lg font-bold text-primary">
                      <span>Total to Pay</span>
                      <span>₦{total.toLocaleString()}</span>
                    </div>
                  </motion.div>
                )}

                <div className="bg-blue-50 dark:bg-blue-900/20 p-3 rounded-lg border border-blue-200 dark:border-blue-800">
                  <p className="text-xs text-blue-700 dark:text-blue-400">
