  --destructive-foreground: 0 0% 98%;

  --border: 240 5.9% 90%;
  --input: 240 5.9% 90%;
  --ring: 148 50% 46%;

  --radius: 0.75rem;

  --chart-1: 148 50% 46%;
  --chart-2: 42 100% 50%;
  --chart-3: 197 37% 24%;
  --chart-4: 43 74% 66%;
